  position: relative;
  display: inline-block;
  width: 52px;
  height: 32px;
  padding: 2px 4px;
  color: $color-white;

  background-color: $color-whitegreen;
  border: 2px solid $color-darkgreen;
  border-radius: 100px;

  -webkit-transition: $toggle-animation-duration;
  transition: $toggle-animation-duration;

  &amp; input { 
    opacity: 0;
    width: 0;
    height: 0;
  }

  &amp; .slider{
    position: absolute;
    cursor: pointer;
    left: 6px;
    bottom: 6px;
    height: 16px;
    width: 16px;
    background-color: $color-darkgreen;
    -webkit-transition: $toggle-animation-duration;
    transition: $toggle-animation-duration;
    border-radius: 50%;
    display:flex;
    align-items: center;
    justify-content: center;
  }
}


