}

.toggle:has(input:disabled:checked) {
  background-color: $color-old-mid-grey;
  border-color: $color-old-mid-grey;
}

.toggle input:disabled:checked + .slider {
  background-color: $color-old-light-grey;
  color: $color-old-mid-grey;
}
